/**
 * @param {Config} config
 * @param {Context} context
 * Do not edit this comment or parameter types. Required for code suggestions
*/
exports.main = function (config, context) {

    function warn(msg) {
        config.warnLog(msg);
    }
    warn("LX-L2TP-ENDPUNKT Addin Active");

    var endpunktList = config.getTableByOid("13.2.61.1");
    var endpunkt = endpunktList.createNewRow();
    endpunkt.setByOid("1", "L2TP-SSID");
    endpunkt.setByOid("2", context.vars.L2TP_Target_IP);
    endpunkt.setByOid("3", "1701");
    endpunkt.setByOid("4", context.device.serialNumber);
    endpunkt.setByOid("5", "123456789"); //PW
    endpunkt.setByOid("6", "0");
    endpunkt.setByOid("7", "0");
    endpunkt.setByOid("8", "1");
    endpunktList.addOrMerge(endpunkt);

        var ethernetList = config.getTableByOid("13.2.61.2");
        var ethernet = ethernetList.createNewRow();
        ethernet.setByOid("1", "L2TP-SSID");
        ethernet.setByOid("2", "L2TP-SSID");
        ethernet.setByOid("3", "0"); //L2TP-Tunnel1
        ethernet.setByOid("4", "1500");
        ethernetList.addOrMerge(ethernet);
};
